select ppc.cuenta, ppc.prioridad
from pmu_priorizacion_cliente ppc
where ppc.eliminado = $1 and ppc.fecha_registro::date = current_date;

select md.id, md.nic, md.priorizacion  
from maestro_db md 
where md.eliminado = $1 and md.fecha_registro::date = current_date;

parameters.jsCode:
const data = $input.all();
const pmu = data[0].json.pmu || [];
const maestro = data[1].json.maestro || [];

return maestro.map(item => ({
  ... item,
  priorizacion: pmu.find(item2 => item2.cuenta == item.nic)?.prioridad || null
}));

